etDate();\n    const prevLastDayDate = new Date(year, month, 0).getDate();\n\n    this.calendarDays = [\n      ...Array.from({ length: firstDayIndex }, (_, i) => new Date(year, month - 1, prevLastDayDate - firstDayIndex + i + 1)),\n      ...Array.from({ length: lastDayDate }, (_, i) => new Date(year, month, i + 1)),\n      ...Array.from({ length: 42 - firstDayIndex - lastDayDate }, (_, i) => new Date(year, month + 1, i + 1))\n    ];\n  }\n\n  generateYears() {\n    const currentYear = new Date().getFullYear();\n    this.years = [];\n    for (let i = currentYear - 25; i <= currentYear + 25; i++) {\n      this.years.push(i);\n    }\n    const currentYearIndex = this.years.indexOf(currentYear);\n    this.currentYearPage = Math.floor(currentYearIndex / this.yearsPerPage);\n    this.updateDisplayedYears();\n  }\n\n  prevMonth() {\n    this.currentDate = new Date(this.currentDate.getFullYear(), this.currentDate.getMonth() - 1, 1);\n    this.selectedYear = this.currentDate.getFullYear();\n    this.selectedMonth = this.currentDate.getMonth();\n    this.generateCalendarDays();\n  }\n\n  nextMonth() {\n    this.currentDate = new Date(this.currentDate.getFullYear(), this.currentDate.getMonth() + 1, 1);\n    this.selectedYear = this.currentDate.getFullYear();\n    this.selectedMonth = this.currentDate.getMonth();\n    this.generateCalendarDays();\n  }\n\n  getYearPageRange(): string {\n    return this.displayedYears.length ? `${this.displayedYears[0]} - ${this.displayedYears[this.displayedYears.length - 1]}` : '';\n  }\n\n  prevYearPage() {\n    if (this.currentYearPage > 0) this.currentYearPage--;\n    this.updateDisplayedYears();\n  }\n\n  nextYearPage() {\n    this.currentYearPage++;\n    const requiredYears = (this.currentYearPage + 1) * this.yearsPerPage;\n    if (requiredYears > this.years.length) {\n      const lastYear = this.years[this.years.length - 1];\n      this.years.push(...Array.from({ length: requiredYears - this.years.length }, (_, i) => lastYear + i + 1));\n    }\n    this.updateDisplayedYears();\n  }\n\n  updateDisplayedYears() {\n    const startIndex = this.currentYearPage * this.yearsPerPage;\n    this.displayedYears = this.years.slice(startIndex, startIndex + this.yearsPerPage);\n  }\n\n  getDateLabel(): string {\n    if (!this.startDate) return '';\n    const format = { month: 'short', day: 'numeric', year: 'numeric' } as const;\n    const start = this.startDate.toLocaleDateString('en-US', format);\n    if (!this.endDate || !this.isRange) return start;\n    const end = this.endDate.toLocaleDateString('en-US', format);\n    return `${start} - ${end}`;\n  }\n\n  isSameDate(date1: Date, date2: Date): boolean {\n    return date1.getDate() === date2.getDate() &&\n      date1.getMonth() === date2.getMonth() &&\n      date1.getFullYear() === date2.getFullYear();\n  }\n}\n","<div class=\"custom-date-field\" cdkOverlayOrigin #trigger=\"cdkOverlayOrigin\" (click)=\"toggleCalendar()\">\n  <mat-icon class=\"date-field-icon-left\">calendar_today</mat-icon>\n  <span class=\"date-field-value\">{{ getDateLabel() || placeholder }}</span>\n  <mat-icon class=\"date-field-icon-close\" *ngIf=\"startDate\" (click)=\"clearDate(); $event.stopPropagation()\">close</mat-icon>\n</div>\n\n<ng-template cdkConnectedOverlay [cdkConnectedOverlayOrigin]=\"trigger\" [cdkConnectedOverlayOpen]=\"showCalendar\"\n  [cdkConnectedOverlayHasBackdrop]=\"true\" [cdkConnectedOverlayBackdropClass]=\"'cdk-overlay-transparent-backdrop'\"\n  (backdropClick)=\"showCalendar = false\">\n  <div class=\"custom-calendar\">\n    <div *ngIf=\"calendarView === 'year'\" class=\"calendar-view\">\n      <div class=\"calendar-header\">\n        <button (click)=\"prevYearPage()\" class=\"nav-btn\"><mat-icon>chevron_left</mat-icon></button>\n        <span class=\"calendar-title\">{{ getYearPageRange() }}</span>\n        <button (click)=\"nextYearPage()\" class=\"nav-btn\"><mat-icon>chevron_right</mat-icon></button>\n      </div>\n      <div class=\"year-grid\">\n        <div *ngFor=\"let year of displayedYears\" class=\"year-item\" (click)=\"selectYear(year)\">{{ year }}</div>\n      </div>\n    </div>\n\n    <div *ngIf=\"calendarView === 'month'\" class=\"calendar-view\">\n      <div class=\"calendar-header\">\n        <button class=\"nav-btn\" style=\"visibility: hidden;\"><mat-icon>chevron_left</mat-icon></button>\n        <span class=\"calendar-title\" (click)=\"backToYearView()\" style=\"cursor: pointer;\">{{ selectedYear }}</span>\n        <button class=\"nav-btn\" style=\"visibility: hidden;\"><mat-icon>chevron_right</mat-icon></button>\n      </div>\n      <div class=\"month-grid\">\n        <div *ngFor=\"let month of monthNames; let i = index\" class=\"month-item\" (click)=\"selectMonth(i)\">{{ month }}</div>\n      </div>\n    </div>\n\n    <div *ngIf=\"calendarView === 'date'\" class=\"calendar-view\">\n      <div class=\"calendar-header\">\n        <button (click)=\"prevMonth()\" class=\"nav-btn\"><mat-icon>chevron_left</mat-icon></button>\n        <span class=\"calendar-title\" (click)=\"backToMonthView()\" style=\"cursor: pointer;\">\n          {{ monthNames[selectedMonth] }} {{ selectedYear }}\n        </span>\n        <button (click)=\"nextMonth()\" class=\"nav-btn\"><mat-icon>chevron_right</mat-icon></button>\n      </div>\n      <div class=\"calendar-weekdays\">\n        <div *ngFor=\"let day of weekDays\" class=\"weekday\">{{ day }}</div>\n      </div>\n      <div class=\"calendar-days\">\n        <div *ngFor=\"let date of calendarDays\" class=\"calendar-day\"\n          [class.other-month]=\"!isCurrentMonth(date)\"\n          [class.in-range]=\"isDateInRange(date)\"\n          [class.start-date]=\"isStartDate(date)\"\n          [class.end-date]=\"isEndDate(date)\"\n          (click)=\"selectDate(date)\">\n          {{ date?.getDate() }}\n        </div>\n      </div>\n    </div>\n\n    <div class=\"calendar-actions\">\n      <button (click)=\"cancelSelection()\">Cancel</button>\n      <button (click)=\"confirmSelection()\">OK</button>\n    </div>\n  </div>\n</ng-template>\n","import { Component, inject, OnInit } from '@angular/core';\nimport { MatIconModule } from '@angular/material/icon';\nimport { CommonModule } from '@angular/common';\nimport { MatDialogRef } from '@angular/material/dialog';\nimport { MatButtonModule } from '@angular/material/button';\nimport { MatCheckboxModule } from '@angular/material/checkbox';\nimport { MatDatepickerModule } from '@angular/material/datepicker';\nimport { MatInputModule } from '@angular/material/input';\nimport { MatFormFieldModule } from '@angular/material/form-field';\nimport { MatNativeDateModule } from '@angular/material/core';\nimport { MatChipsModule } from '@angular/material/chips';\nimport { MatAutocompleteModule } from '@angular/material/autocomplete';\nimport { FormsModule, ReactiveFormsModule } from '@angular/forms';\nimport { FormControl } from '@angular/forms';\nimport { trigger, style, transition, animate } from '@angular/animations';\nimport { OverlayModule } from '@angular/cdk/overlay';\nimport { PortService } from '../../pages/master/port/port.service';\nimport { DisbursementService } from '../../pages/disbursment/disbursement.component.service';\nimport { formatToLocalISOString, } from '../../pages/pda/pda.model';\nimport { CustomDatePickerComponent } from '../custom-date-picker/custom-date-picker.component';\n\ninterface PortAgentFilter {\n  company_name: string;\n  selected: boolean;\n}\n\ninterface CountryFilter {\n  country_id: number;\n  country_name: string;\n  selected: boolean;\n}\n\ninterface PICFilter {\n  user_id: number;\n  user_name: string;\n  selected: boolean;\n}\n\ninterface StatusFilter {\n  status: string;\n  selected: boolean;\n  pda: boolean;\n  fda: boolean;\n}\n\ninterface PortFilter {\n  name: string;\n  country_id: number;\n  selected: boolean;\n}\n\ninterface VesselFilter {\n  company_id: number;\n  name: string;\n  selected: boolean;\n}\n\ninterface ClientFilter {\n  client_id: number;\n  name: string;\n  selected: boolean;\n}\n\ninterface VoyageFilter {\n  voyage_id: number;\n  name: string;\n  selected: boolean;\n}\n\ninterface LossPreventionFilter {\n  type: string;\n  enabled: boolean;\n  min: number | null;\n  max: number | null;\n}\n\ninterface OverDueFilter {\n  type: string;\n  min: number | null;\n  max: number | null;\n}\n\n@Component({\n  selector: 'app-disbursement-filter',\n  standalone: true,\n  imports: [\n    MatIconModule,\n    CommonModule,\n    MatButtonModule,\n    MatCheckboxModule,\n    MatDatepickerModule,\n    MatInputModule,\n    MatFormFieldModule,\n    MatNativeDateModule,\n    MatChipsModule,\n    MatAutocompleteModule,\n    FormsModule,\n    ReactiveFormsModule,\n    OverlayModule,\n    CustomDatePickerComponent\n  ],\n  templateUrl: './disbursement-filter.component.html',\n  styleUrl: './disbursement-filter.component.css',\n  animations: [\n    trigger('slideDown', [\n      transition(':enter', [\n        style({\n          opacity: 0,\n          transform: 'translateY(-30px)'\n        }),\n        animate('400ms cubic-bezier(0.35, 0, 0.25, 1)',\n          style({\n            opacity: 1,\n            transform: 'translateY(0)'\n          })\n        )\n      ])\n    ])\n  ]\n})\nexport class DisbursementFilterComponent implements OnInit {\n  portAgentList: PortAgentFilter[] = [];\n  filteredPortAgentList: PortAgentFilter[] = [];\n  countryList: CountryFilter[] = [];\n  filteredCountryList: CountryFilter[] = [];\n  picList: PICFilter[] = [];\n  filteredPICList: PICFilter[] = [];\n  statusList: StatusFilter[] = [];\n  filteredStatusList: StatusFilter[] = [];\n  portList: PortFilter[] = [];\n  filteredPortList: PortFilter[] = [];\n  vesselList: VesselFilter[] = [];\n  filteredVesselList: VesselFilter[] = [];\n  clientList: ClientFilter[] = [];\n  filteredClientList: ClientFilter[] = [];\n  voyageList: VoyageFilter[] = [];\n  filteredVoyageList: VoyageFilter[] = [];\n  voyageControl = new FormControl('');\n  selectedVoyages: string[] = [];\n  lossPreventionList: LossPreventionFilter[] = [\n    { type: 'PDA Savings', enabled: false, min: null, max: null },\n    { type: 'FDA Savings', enabled: false, min: null, max: null },\n    { type: 'Total Savings', enabled: false, min: null, max: null },\n    { type: 'Roe Loss', enabled: false, min: null, max: null },\n\n  ];\n  overDueList: OverDueFilter[] = [\n    { type: 'PDA Over Due', min: null, max: null },\n    { type: 'FDA Over Due', min: null, max: null }\n  ];\n  searchText: string = '';\n  countrySearchText: string = '';\n  picSearchText: string = '';\n  statusSearchText: string = '';\n  portSearchText: string = '';\n  vesselSearchText: string = '';\n  clientSearchText: string = '';\n  voyageSearchText: string = '';\n  lossPreventionSearchText: string = '';\n  overDueSearchText: string = '';\n\n  // ETA-ETD date selection\n  etaDate: Date | null = null;\n  etdDate: Date | null = null;\n\n\n\n  // PDA date selection\n  pdaStartDate: Date | null = null;\n  pdaEndDate: Date | null = null;\n\n  // FDA date selection\n  fdaStartDate: Date | null = null;\n  fdaEndDate: Date | null = null;\n\n  selectedFilters = {\n    page_size: 25,\n    page: 1,\n    query: \"\",\n    filter: {\n      eta_etd: { from_date: null as string | null, to_date: null as string | null },\n      pda_processing_date: { from_date: null as string | null, to_date: null as string | null },\n      fda_processing_date: { from_date: null as string | null, to_date: null as string | null },\n      port_agent: [] as string[],\n      country: [] as string[],\n      vessel: [] as string[],\n      port: [] as string[],\n      pic: [] as number[],\n      status: [] as string[],\n      client: [] as string[],\n      voyage: [] as string[],\n      roe_loss: { min_value: null as number | null, max_value: null as number | null, has_data: 'N' as 'Y' | 'N' },\n      loss_prevention_pda: { min_value: null as number | null, max_value: null as number | null, has_data: 'N' as 'Y' | 'N' },\n      loss_prevention_fda: { min_value: null as number | null, max_value: null as number | null, has_data: 'N' as 'Y' | 'N' },\n      total_loss_prevention: { min_value: null as number | null, max_value: null as number | null, has_data: 'N' as 'Y' | 'N' },\n      pda_over_due: { min_value: null as number | null, max_value: null as number | null },\n      fda_over_due: { min_value: null as number | null, max_value: null as number | null },\n    }\n  };\n\n  constructor(private portService: PortService, private disbursementService: DisbursementService) { }\n\n  private dialogRef = inject(MatDialogRef<DisbursementFilterComponent>);\n\n  activeTabIndex = 0;\n\n  tabs = [\n    { label: 'Date' },\n    { label: 'Status' },\n    { label: 'PIC' },\n    { label: 'Vessel' },\n    { label: 'Port' },\n    { label: 'Country' },\n    { label: 'Port Agent' },\n    { label: 'Client' },\n    { label: 'Voyage' },\n    { label: 'Savings' },\n    { label: 'Over Due' },\n  ];\n\n  ngOnInit(): void {\n    this.selectTab(0);\n    this.fetchMasterData();\n    this.loadFiltersFromSession();\n\n    this.voyageControl.valueChanges.subscribe(value => {\n      this.filterVoyages();\n    });\n  }\n\n  fetchMasterData() {\n    const params = {\n      fields: ['all']\n    };\n\n    this.portService.getFilterMasterData(params).subscribe({\n      next: (response: any) => {\n\n        const status = response.status || [];\n        this.statusList = status.map((status: any) => ({\n          status: status.status,\n          selected: false,\n          pda: false,\n          fda: false\n        }));\n        this.statusList.push({\n          status: 'Final Status',\n          selected: false,\n          pda: false,\n          fda: false\n        });\n        this.statusList.push({\n          status: 'Inactive',\n          selected: false,\n          pda: false,\n          fda: false\n        });\n        this.filteredStatusList = [...this.statusList];\n\n        const portAgents = response.port_agent || [];\n        this.portAgentList = portAgents.map((agent: any) => ({\n          company_name: agent.company_name,\n          selected: false\n        }));\n        this.filteredPortAgentList = [...this.portAgentList];\n\n        const countries = response.country || [];\n        this.countryList = countries.map((country: any) => ({\n          country_id: country.country_id,\n          country_name: country.name,\n          selected: false\n        }));\n        this.filteredCountryList = [...this.countryList];\n\n        const pic = response.pic || []\n        this.picList = pic.map((pic: any) => ({\n          user_id: pic.user,\n          user_name: pic.names,\n          selected: false\n        }));\n        this.filteredPICList = [...this.picList];\n\n        const ports = response.port || [];\n        this.portList = ports.map((port: any) => ({\n          name: port.name,\n          country_id: port.country_id,\n          selected: false\n        }));\n        this.filteredPortList = [...this.portList];\n\n        const vessels = response.vessels || [];\n        this.vesselList = vessels.map((vessel: any) => ({\n          company_id: vessel.company_id,\n          name: vessel.name,\n          selected: false\n        }));\n        this.filteredVesselList = [...this.vesselList];\n\n        const clients = response.client || [];\n        this.clientList = clients.map((client: any) => ({\n          client_id: client.client_id,\n          name: client.name,\n          selected: false\n        }));\n        this.filteredClientList = [...this.clientList];\n\n        const voyages = response.voyage || [];\n        this.voyageList = voyages.map((voyage: any) => ({\n          voyage_id: voyage.voyage_id,\n          name: voyage.name,\n          selected: false\n        }));\n        this.filteredVoyageList = [...this.voyageList];\n\n\n\n\n      },\n      error: (error: any) => {\n        // Handle errors here\n      }\n    });\n  }\n\n  selectTab(index: number) {\n    this.activeTabIndex = index;\n  }\n\n  filterPortAgents() {\n    const search = this.searchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredPortAgentList = [...this.portAgentList];\n    } else {\n      this.filteredPortAgentList = this.portAgentList.filter(agent =>\n        agent.company_name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterCountries() {\n    const search = this.countrySearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredCountryList = [...this.countryList];\n    } else {\n      this.filteredCountryList = this.countryList.filter(country =>\n        country.country_name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterPICs() {\n    const search = this.picSearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredPICList = [...this.picList];\n    } else {\n      this.filteredPICList = this.picList.filter(pic =>\n        pic.user_name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterStatuses() {\n    const search = this.statusSearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredStatusList = [...this.statusList];\n    } else if ('fda'.startsWith(search) || 'pda'.startsWith(search)) {\n      this.filteredStatusList = [...this.statusList];\n    } else {\n      this.filteredStatusList = this.statusList.filter(status => {\n        const statusLower = status.status.toLowerCase();\n\n        if (search.startsWith('pda ')) {\n          const searchTerm = search.substring(4);\n          return statusLower.includes(searchTerm);\n        } else if (search.startsWith('fda ')) {\n          const searchTerm = search.substring(4);\n          return statusLower.includes(searchTerm);\n        } else {\n          return statusLower.includes(search);\n        }\n      });\n    }\n  }\n\n  filterPorts() {\n    const search = this.portSearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredPortList = [...this.portList];\n    } else {\n      this.filteredPortList = this.portList.filter(port =>\n        port.name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterVessels() {\n    const search = this.vesselSearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredVesselList = [...this.vesselList];\n    } else {\n      this.filteredVesselList = this.vesselList.filter(vessel =>\n        vessel.name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterClients() {\n    const search = this.clientSearchText.toLowerCase().trim();\n    if (!search) {\n      this.filteredClientList = [...this.clientList];\n    } else {\n      this.filteredClientList = this.clientList.filter(client =>\n        client.name.toLowerCase().includes(search)\n      );\n    }\n  }\n\n  filterVoyages() {\n    const search = (this.voyageControl.value || '').toLowerCase().trim();\n    if (!search) {\n      this.filteredVoyageList = [...this.voyageList];\n    } else {\n      this.filteredVoyageList = this.voyageList.filter(voyage =>\n        voyage.name.toLowerCase().includes(search) && !this.selectedVoyages.includes(voyage.name)\n      );\n    }\n  }\n\n  onVoyageSelected(event: any) {\n    const voyageName = event.option.value;\n    if (!this.selectedVoyages.includes(voyageName)) {\n      this.selectedVoyages.push(voyageName);\n      const voyage = this.voyageList.find(v => v.name === voyageName);\n      if (voyage) voyage.selected = true;\n    }\n    this.voyageControl.setValue('');\n    this.saveFiltersToSession();\n  }\n\n  addCustomVoyage() {\n    const voyageName = this.voyageControl.value?.trim();\n    if (voyageName && !this.selectedVoyages.includes(voyageName)) {\n      this.selectedVoyages.push(voyageName);\n    }\n    this.voyageControl.setValue('');\n    this.saveFiltersToSession();\n  }\n\n  removeVoyage(voyageName: string) {\n    this.selectedVoyages = this.selectedVoyages.filter(v => v !== voyageName);\n    const voyage = this.voyageList.find(v => v.name === voyageName);\n    if (voyage) voyage.selected = false;\n    this.saveFiltersToSession();\n  }\n\n\n\n\n\n  onPortAgentChange(agent: PortAgentFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onCountryChange(country: CountryFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onPICChange(pic: PICFilter) {\n    this.saveFiltersToSession();\n  }\n\n  toggleStatus(status: StatusFilter, type: 'pda' | 'fda' | 'both') {\n    if (type === 'pda') {\n      status.pda = !status.pda;\n    } else if (type === 'fda') {\n      status.fda = !status.fda;\n    } else if (type === 'both') {\n      if (status.pda && status.fda) {\n        status.pda = false;\n        status.fda = false;\n      } else {\n        status.pda = true;\n        status.fda = true;\n      }\n    }\n    this.saveFiltersToSession();\n  }\n\n  getSelectedStatuses(): string[] {\n    const selected: string[] = [];\n    this.statusList.forEach(status => {\n      if (status.status === 'Final Status' && (status.pda || status.fda)) {\n        selected.push('Final Status');\n      } else {\n        if (status.pda) selected.push(`PDA ${status.status}`);\n        if (status.fda) selected.push(`FDA ${status.status}`);\n      }\n    });\n    return selected;\n  }\n\n  removeStatusChip(chip: string) {\n    const isPDA = chip.startsWith('PDA');\n    const isFDA = chip.startsWith('FDA');\n    const statusName = chip.replace(/^(PDA|FDA) /, '');\n\n    const status = this.statusList.find(s => s.status === statusName);\n    if (status) {\n      if (isPDA) status.pda = false;\n      if (isFDA) status.fda = false;\n      this.saveFiltersToSession();\n    }\n  }\n\n  onPortChange(port: PortFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onVesselChange(vessel: VesselFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onClientChange(client: ClientFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onVoyageChange(voyage: VoyageFilter) {\n    this.saveFiltersToSession();\n  }\n\n  onLossPreventionChange() {\n    this.saveFiltersToSession();\n  }\n\n  onOverDueChange() {\n    this.saveFiltersToSession();\n  }\n\n  clearDateFilter() {\n    this.etaDate = null;\n    this.etdDate = null;\n    this.selectedFilters.filter.eta_etd = { from_date: null, to_date: null };\n    this.saveFiltersToSession();\n  }\n\n  onEtaDateChange() {\n    this.selectedFilters.filter.eta_etd.from_date = this.etaDate ? formatToLocalISOString(this.etaDate) : null;\n    this.saveFiltersToSession();\n  }\n\n  onEtdDateChange() {\n    this.selectedFilters.filter.eta_etd.to_date = this.etdDate ? formatToLocalISOString(this.etdDate) : null;\n    this.saveFiltersToSession();\n  }\n\n  onPdaDateChange(event: { startDate: Date | null, endDate: Date | null }) {\n    this.pdaStartDate = event.startDate;\n    this.pdaEndDate = event.endDate;\n    this.selectedFilters.filter.pda_processing_date = {\n      from_date: event.startDate ? formatToLocalISOString(event.startDate) : null,\n      to_date: event.endDate ? formatToLocalISOString(event.endDate) : null\n    };\n    this.saveFiltersToSession();\n  }\n\n  onFdaDateChange(event: { startDate: Date | null, endDate: Date | null }) {\n    this.fdaStartDate = event.startDate;\n    this.fdaEndDate = event.endDate;\n    this.selectedFilters.filter.fda_processing_date = {\n      from_date: event.startDate ? formatToLocalISOString(event.startDate) : null,\n      to_date: event.endDate ? formatToLocalISOString(event.endDate) : null\n    };\n    this.saveFiltersToSession();\n  }\n\n  clearPdaFilter() {\n    this.pdaStartDate = null;\n    this.pdaEndDate = null;\n    this.selectedFilters.filter.pda_processing_date = { from_date: null, to_date: null };\n    this.saveFiltersToSession();\n  }\n\n  clearFdaFilter() {\n    this.fdaStartDate = null;\n    this.fdaEndDate = null;\n    this.selectedFilters.filter.fda_processing_date = { from_date: null, to_date: null };\n    this.saveFiltersToSession();\n  }\n\n  clearStatusFilter() {\n    this.statusList.forEach(status => {\n      status.selected = false;\n      status.pda = false;\n      status.fda = false;\n    });\n    this.selectedFilters.filter.status = [];\n    this.statusSearchText = '';\n    this.filteredStatusList = [...this.statusList];\n    this.saveFiltersToSession();\n  }\n\n  clearPICFilter() {\n    this.picList.forEach(pic => pic.selected = false);\n    this.selectedFilters.filter.pic = [];\n    this.picSearchText = '';\n    this.filteredPICList = [...this.picList];\n    this.saveFiltersToSession();\n  }\n\n  clearVesselFilter() {\n    this.vesselList.forEach(vessel => vessel.selected = false);\n    this.selectedFilters.filter.vessel = [];\n    this.vesselSearchText = '';\n    this.filteredVesselList = [...this.vesselList];\n    this.saveFiltersToSession();\n  }\n\n  clearPortFilter() {\n    this.portList.forEach(port => port.selected = false);\n    this.selectedFilters.filter.port = [];\n    this.portSearchText = '';\n    this.filteredPortList = [...this.portList];\n    this.saveFiltersToSession();\n  }\n\n  clearCountryFilter() {\n    this.countryList.forEach(country => country.selected = false);\n    this.selectedFilters.filter.country = [];\n    this.countrySearchText = '';\n    this.filteredCountryList = [...this.countryList];\n    this.saveFiltersToSession();\n  }\n\n  clearPortAgentFilter() {\n    this.portAgentList.forEach(agent => agent.selected = false);\n    this.selectedFilters.filter.port_agent = [];\n    this.searchText = '';\n    this.filteredPortAgentList = [...this.portAgentList];\n    this.saveFiltersToSession();\n  }\n\n  clearClientFilter() {\n    this.clientList.forEach(client => client.selected = false);\n    this.selectedFilters.filter.client = [];\n    this.clientSearchText = '';\n    this.filteredClientList = [...this.clientList];\n    this.saveFiltersToSession();\n  }\n\n  clearVoyageFilter() {\n    this.voyageList.forEach(voyage => voyage.selected = false);\n    this.selectedFilters.filter.voyage = [];\n    this.selectedVoyages = [];\n    this.voyageControl.setValue('');\n    this.voyageSearchText = '';\n    this.filteredVoyageList = [...this.voyageList];\n    this.saveFiltersToSession();\n  }\n\n  clearLossPreventionFilter() {\n    this.lossPreventionList.forEach(lp => {\n      lp.enabled = false;\n      lp.min = null;\n      lp.max = null;\n    });\n    this.selectedFilters.filter.roe_loss = { min_value: null, max_value: null, has_data: 'N' };\n    this.selectedFilters.filter.loss_prevention_pda = { min_value: null, max_value: null, has_data: 'N' };\n    this.selectedFilters.filter.loss_prevention_fda = { min_value: null, max_value: null, has_data: 'N' };\n    this.selectedFilters.filter.total_loss_prevention = { min_value: null, max_value: null, has_data: 'N' };\n    this.lossPreventionSearchText = '';\n    this.saveFiltersToSession();\n  }\n\n  clearOverDueFilter() {\n    this.overDueList.forEach(od => {\n      od.min = null;\n      od.max = null;\n    });\n    this.selectedFilters.filter.pda_over_due = { min_value: null, max_value: null };\n    this.selectedFilters.filter.fda_over_due = { min_value: null, max_value: null };\n    this.overDueSearchText = '';\n    this.saveFiltersToSession();\n  }\n\n  clearAllFilters() {\n    this.clearDateFilter();\n    this.clearPdaFilter();\n    this.clearFdaFilter();\n    this.clearStatusFilter();\n    this.clearPICFilter();\n    this.clearVesselFilter();\n    this.clearPortFilter();\n    this.clearCountryFilter();\n    this.clearPortAgentFilter();\n    this.clearClientFilter();\n    this.clearVoyageFilter();\n    this.clearLossPreventionFilter();\n    this.clearOverDueFilter();\n  }\n\n  applyFilters() {\n    this.selectedFilters.filter.port_agent = this.portAgentList\n      .filter(agent => agent.selected)\n      .map(agent => agent.company_name);\n\n    this.selectedFilters.filter.country = this.countryList\n      .filter(country => country.selected)\n      .map(country => String(country.country_name));\n\n    this.selectedFilters.filter.pic = this.picList\n      .filter(pic => pic.selected)\n      .map(pic => pic.user_id);\n\n    const selectedStatuses: string[] = [];\n    this.statusList.forEach(status => {\n      if (status.status === 'Final Status' && (status.pda || status.fda)) {\n        selectedStatuses.push('Final Status');\n      } else {\n        if (status.pda) selectedStatuses.push(`PDA ${status.status}`);\n        if (status.fda) selectedStatuses.push(`FDA ${status.status}`);\n      }\n    });\n    this.selectedFilters.filter.status = selectedStatuses;\n\n    this.selectedFilters.filter.eta_etd = {\n      from_date: this.etaDate ? formatToLocalISOString(this.etaDate) : null,\n      to_date: this.etdDate ? formatToLocalISOString(this.etdDate) : null\n    };\n\n    this.selectedFilters.filter.pda_processing_date = {\n      from_date: this.pdaStartDate ? formatToLocalISOString(this.pdaStartDate) : null,\n      to_date: this.pdaEndDate ? formatToLocalISOString(this.pdaEndDate) : null\n    };\n\n    this.selectedFilters.filter.fda_processing_date = {\n      from_date: this.fdaStartDate ? formatToLocalISOString(this.fdaStartDate) : null,\n      to_date: this.fdaEndDate ? formatToLocalISOString(this.fdaEndDate) : null\n    };\n\n    this.selectedFilters.filter.vessel = this.vesselList\n      .filter(vessel => vessel.selected)\n      .map(vessel => String(vessel.name));\n\n    this.selectedFilters.filter.port = this.portList\n      .filter(port => port.selected)\n      .map(port => String(port.name));\n\n    this.selectedFilters.filter.client = this.clientList\n      .filter(client => client.selected)\n      .map(client => String(client.name));\n\n    this.selectedFilters.filter.voyage = this.selectedVoyages;\n\n    // Loss Prevention filters\n    const roeLoss = this.lossPreventionList.find(lp => lp.type === 'Roe Loss');\n    this.selectedFilters.filter.roe_loss = {\n      min_value: roeLoss?.enabled ? roeLoss.min : null,\n      max_value: roeLoss?.enabled ? roeLoss.max : null,\n      has_data: roeLoss?.enabled ? 'Y' : 'N'\n    };\n\n    const pdaLoss = this.lossPreventionList.find(lp => lp.type === 'PDA Savings');\n    this.selectedFilters.filter.loss_prevention_pda = {\n      min_value: pdaLoss?.enabled ? pdaLoss.min : null,\n      max_value: pdaLoss?.enabled ? pdaLoss.max : null,\n      has_data: pdaLoss?.enabled ? 'Y' : 'N'\n    };\n\n    const fdaLoss = this.lossPreventionList.find(lp => lp.type === 'FDA Savings');\n    this.selectedFilters.filter.loss_prevention_fda = {\n      min_value: fdaLoss?.enabled ? fdaLoss.min : null,\n      max_value: fdaLoss?.enabled ? fdaLoss.max : null,\n      has_data: fdaLoss?.enabled ? 'Y' : 'N'\n    };\n\n    const totalLoss = this.lossPreventionList.find(lp => lp.type === 'Total Savings');\n    this.selectedFilters.filter.total_loss_prevention = {\n      min_value: totalLoss?.enabled ? totalLoss.min : null,\n      max_value: totalLoss?.enabled ? totalLoss.max : null,\n      has_data: totalLoss?.enabled ? 'Y' : 'N'\n    };\n\n    // Over Due filters\n    const pdaOverDue = this.overDueList.find(od => od.type === 'PDA Over Due');\n    this.selectedFilters.filter.pda_over_due = {\n      min_value: pdaOverDue?.min ?? null,\n      max_value: pdaOverDue?.max ?? null\n    };\n\n    const fdaOverDue = this.overDueList.find(od => od.type === 'FDA Over Due');\n    this.selectedFilters.filter.fda_over_due = {\n      min_value: fdaOverDue?.min ?? null,\n      max_value: fdaOverDue?.max ?? null,\n    };\n\n    this.dialogRef.close(this.selectedFilters);\n  }\n\n  closeFilter() {\n    this.saveFiltersToSession();\n    this.dialogRef.close();\n  }\n\n  saveFiltersToSession() {\n    const filterState = {\n      portAgentList: this.portAgentList,\n      countryList: this.countryList,\n      picList: this.picList,\n      statusList: this.statusList,\n      portList: this.portList,\n      vesselList: this.vesselList,\n      clientList: this.clientList,\n      voyageList: this.voyageList,\n      selectedVoyages: this.selectedVoyages,\n      lossPreventionList: this.lossPreventionList,\n      overDueList: this.overDueList,\n      rowLoss: this.selectedFilters.filter.roe_loss,\n      pdaLossPrevention: this.selectedFilters.filter.loss_prevention_pda,\n      fdaLossPrevention: this.selectedFilters.filter.loss_prevention_fda,\n      totalLossPrevention: this.selectedFilters.filter.total_loss_prevention,\n      pdaOverDue: this.selectedFilters.filter.pda_over_due,\n      fdaOverDue: this.selectedFilters.filter.fda_over_due,\n      etaDate: this.etaDate,\n      etdDate: this.etdDate,\n      pdaStartDate: this.pdaStartDate,\n      pdaEndDate: this.pdaEndDate,\n      fdaStartDate: this.fdaStartDate,\n      fdaEndDate: this.fdaEndDate\n    };\n    sessionStorage.setItem('disbursementFilterState', JSON.stringify(filterState));\n  }\n\n  loadFiltersFromSession() {\n    const savedState = sessionStorage.getItem('disbursementFilterState');\n    if (savedState) {\n      const filterState = JSON.parse(savedState);\n\n      // Wait for master data to load first\n      const checkDataInterval = setInterval(() => {\n        if (this.portAgentList.length > 0 || this.countryList.length > 0) {\n          clearInterval(checkDataInterval);\n\n          // Restore port agents\n          if (filterState.portAgentList) {\n            filterState.portAgentList.forEach((savedAgent: PortAgentFilter) => {\n              const agent = this.portAgentList.find(a => a.company_name === savedAgent.company_name);\n              if (agent) agent.selected = savedAgent.selected;\n            });\n            this.filteredPortAgentList = [...this.portAgentList];\n          }\n\n          // Restore countries\n          if (filterState.countryList) {\n            filterState.countryList.forEach((savedCountry: CountryFilter) => {\n              const country = this.countryList.find(c => c.country_id === savedCountry.country_id);\n              if (country) country.selected = savedCountry.selected;\n            });\n            this.filteredCountryList = [...this.countryList];\n          }\n\n          // Restore PICs\n          if (filterState.picList) {\n            filterState.picList.forEach((savedPIC: PICFilter) => {\n              const pic = this.picList.find(p => p.user_id === savedPIC.user_id);\n              if (pic) pic.selected = savedPIC.selected;\n            });\n            this.filteredPICList = [...this.picList];\n          }\n\n          // Restore statuses\n          if (filterState.statusList) {\n            filterState.statusList.forEach((savedStatus: StatusFilter) => {\n              const status = this.statusList.find(s => s.status === savedStatus.status);\n              if (status) {\n                status.selected = savedStatus.selected;\n                status.pda = savedStatus.pda;\n                status.fda = savedStatus.fda;\n              }\n            });\n            this.filteredStatusList = [...this.statusList];\n          }\n\n          // Restore ports\n          if (filterState.portList) {\n            filterState.portList.forEach((savedPort: PortFilter) => {\n              const port = this.portList.find(p => p.name === savedPort.name);\n              if (port) port.selected = savedPort.selected;\n            });\n            this.filteredPortList = [...this.portList];\n          }\n\n          // Restore vessels\n          if (filterState.vesselList) {\n            filterState.vesselList.forEach((savedVessel: VesselFilter) => {\n              const vessel = this.vesselList.find(v => v.name === savedVessel.name);\n              if (vessel) vessel.selected = savedVessel.selected;\n            });\n            this.filteredVesselList = [...this.vesselList];\n          }\n\n          // Restore clients\n          if (filterState.clientList) {\n            filterState.clientList.forEach((savedClient: ClientFilter) => {\n              const client = this.clientList.find(c => c.client_id === savedClient.client_id);\n              if (client) client.selected = savedClient.selected;\n            });\n            this.filteredClientList = [...this.clientList];\n          }\n\n          // Restore voyages\n          if (filterState.voyageList) {\n            filterState.voyageList.forEach((savedVoyage: VoyageFilter) => {\n              const voyage = this.voyageList.find(v => v.voyage_id === savedVoyage.voyage_id);\n              if (voyage) voyage.selected = savedVoyage.selected;\n            });\n            this.filteredVoyageList = [...this.voyageList];\n          }\n\n          // Restore selected voyages\n          if (filterState.selectedVoyages) {\n            this.selectedVoyages = filterState.selectedVoyages;\n          }\n\n          // Restore loss prevention\n          if (filterState.lossPreventionList) {\n            filterState.lossPreventionList.forEach((savedLP: LossPreventionFilter) => {\n              const lp = this.lossPreventionList.find(l => l.type === savedLP.type);\n              if (lp) {\n                lp.enabled = savedLP.enabled;\n                lp.min = savedLP.min;\n                lp.max = savedLP.max;\n              }\n            });\n          }\n\n          // Restore loss prevention filter values\n          if (filterState.rowLoss) {\n            this.selectedFilters.filter.roe_loss = filterState.rowLoss;\n          }\n          if (filterState.pdaLossPrevention) {\n            this.selectedFilters.filter.loss_prevention_pda = filterState.pdaLossPrevention;\n          }\n          if (filterState.fdaLossPrevention) {\n            this.selectedFilters.filter.loss_prevention_fda = filterState.fdaLossPrevention;\n          }\n          if (filterState.totalLossPrevention) {\n            this.selectedFilters.filter.total_loss_prevention = filterState.totalLossPrevention;\n          }\n\n          // Restore over due\n          if (filterState.overDueList) {\n            filterState.overDueList.forEach((savedOD: OverDueFilter) => {\n              const od = this.overDueList.find(o => o.type === savedOD.type);\n              if (od) {\n                od.min = savedOD.min;\n                od.max = savedOD.max;\n              }\n            });\n          }\n\n          // Restore over due filter values\n          if (filterState.pdaOverDue) {\n            this.selectedFilters.filter.pda_over_due = filterState.pdaOverDue;\n          }\n          if (filterState.fdaOverDue) {\n            this.selectedFilters.filter.fda_over_due = filterState.fdaOverDue;\n          }\n\n          // Restore dates\n          if (filterState.etaDate) {\n            this.etaDate = new Date(filterState.etaDate);\n          }\n          if (filterState.etdDate) {\n            this.etdDate = new Date(filterState.etdDate);\n          }\n          if (filterState.pdaStartDate) {\n            this.pdaStartDate = new Date(filterState.pdaStartDate);\n          }\n          if (filterState.pdaEndDate) {\n            this.pdaEndDate = new Date(filterState.pdaEndDate);\n          }\n          if (filterState.fdaStartDate) {\n            this.fdaStartDate = new Date(filterState.fdaStartDate);\n          }\n          if (filterState.fdaEndDate) {\n            this.fdaEndDate = new Date(filterState.fdaEndDate);\n          }\n        }\n      }, 100);\n\n      // Clear interval after 5 seconds to prevent infinite loop\n      setTimeout(() => clearInterval(checkDataInterval), 5000);\n    }\n  }\n\n\n  // method filter the fda status\n  shouldShowFdaStatus(status: StatusFilter): boolean {\n    return status.status !== 'On-Hold' &&\n      status.status !== 'Final Status' &&\n      status.status !== 'Submitted' &&\n      status.status !== 'Re-Submitted' &&\n      status.status !== 'Requested' &&\n      status.status !== 'Inactive' &&\n      status.status !== 'Re-Requested';\n  }\n\n  // method to display the check icon if the data selected\n  hasFilterApplied(index: number): boolean {\n    switch (index) {\n      case 0: return !!(this.etaDate || this.etdDate || this.pdaStartDate || this.fdaStartDate);\n      case 1: return this.statusList.some(s => s.pda || s.fda);\n      case 2: return this.picList.some(p => p.selected);\n      case 3: return this.vesselList.some(v => v.selected);\n      case 4: return this.portList.some(p => p.selected);\n      case 5: return this.countryList.some(c => c.selected);\n      case 6: return this.portAgentList.some(a => a.selected);\n      case 7: return this.clientList.some(c => c.selected);\n      case 8: return this.selectedVoyages.length > 0;\n      case 9: return this.lossPreventionList.some(lp => lp.enabled);\n      case 10: return this.overDueList.some(od => od.min !== null || od.max !== null);\n      default: return false;\n    }\n  }\n}\n","<section>\n    <div class=\"filter-header\">\n        <div>\n            <p class=\"filter-title\">Filter</p>\n        </div>\n        <button class=\"close-button\" (click)=\"closeFilter()\" mat-icon-button>\n            <mat-icon fontSet=\"material-symbols-outlined\">close</mat-icon>\n        </button>\n    </div>\n    <div class=\"filter-content\">\n        <div class=\"custom-tabs-container\">\n            <!-- Tab Navigation -->\n            <div class=\"tab-nav\">\n                <button *ngFor=\"let tab of tabs; let i = index\" class=\"tab-button\" [class.active]=\"activeTabIndex === i\"\n                    (click)=\"selectTab(i)\">\n                    {{ tab.label }}\n                    <mat-icon *ngIf=\"hasFilterApplied(i)\"\n                        style=\"font-size: 19px; width: 16px; height: 16px; margin-left: 4px; color: #51d151;\">check</mat-icon>\n                </button>\n            </div>\n\n            <!-- Tab Content -->\n            <div class=\"tab-content-wrapper\">\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 0\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearDateFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div style=\"display: flex; gap: 16px; margin-bottom: 16px; margin-top: 20px;\">\n                            <div style=\"flex: 1;\">\n                                <span style=\"font-weight: bold; display: block; margin-bottom: 8px;\">ETA</span>\n                                <app-custom-date-picker placeholder=\"Select ETA\" [isRange]=\"false\"\n                                    [(startDate)]=\"etaDate\" (startDateChange)=\"onEtaDateChange()\">\n                                </app-custom-date-picker>\n                            </div>\n                            <div style=\"flex: 1;\">\n                                <span style=\"font-weight: bold; display: block; margin-bottom: 8px;\">ETD</span>\n                                <app-custom-date-picker placeholder=\"Select ETD\" [isRange]=\"false\"\n                                    [(startDate)]=\"etdDate\" (startDateChange)=\"onEtdDateChange()\">\n                                </app-custom-date-picker>\n                            </div>\n                        </div>\n                    </div>\n                    <hr>\n                    <div class=\"tab-content\" style=\"margin-top: 16px;\">\n                        <div style=\"display: flex; justify-content: space-between; align-items: center;\">\n                            <span style=\"font-weight: bold;\">PDA processing date</span>\n                        </div>\n                    </div>\n                    <div class=\"filter-options\">\n                        <app-custom-date-picker placeholder=\"Select date range\" [isRange]=\"true\"\n                            [(startDate)]=\"pdaStartDate\" [(endDate)]=\"pdaEndDate\"\n                            (dateChange)=\"onPdaDateChange($event)\">\n                        </app-custom-date-picker>\n                    </div>\n                    <hr>\n                    <div class=\"tab-content\" style=\"margin-top: 16px;\">\n                        <div style=\"display: flex; justify-content: space-between; align-items: center;\">\n                            <span style=\"font-weight: bold;\">FDA processing date</span>\n                        </div>\n                    </div>\n                    <div class=\"filter-options\">\n                        <app-custom-date-picker placeholder=\"Select date range\" [isRange]=\"true\"\n                            [(startDate)]=\"fdaStartDate\" [(endDate)]=\"fdaEndDate\"\n                            (dateChange)=\"onFdaDateChange($event)\">\n                        </app-custom-date-picker>\n                    </div>\n\n\n\n\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 1\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearStatusFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n\n                    <div class=\"filter-options\">\n                        <div class=\"checkbox-list status-filter-list\">\n\n                            <!-- PDA -->\n                            <div class=\"status-group\">\n                                <div class=\"status-group-title\">PDA</div>\n\n                                <div class=\"status-chip-wrapper\">\n                                    <div *ngFor=\"let status of filteredStatusList\">\n                                        <div *ngIf=\"status.status !== 'On-Hold' && status.status !== 'Final Status'\"\n                                            class=\"status-filter-chip\" [class.selected]=\"status.pda\"\n                                            (click)=\"toggleStatus(status, 'pda')\">\n                                            <div class=\"status-filter-text\">{{ status.status }}</div>\n                                        </div>\n                                    </div>\n                                </div>\n                            </div>\n\n                            <!-- FDA -->\n                            <div class=\"status-group\">\n                                <div class=\"status-group-title\">FDA</div>\n\n                                <div class=\"status-chip-wrapper\">\n                                    <div *ngFor=\"let status of filteredStatusList\">\n                                        <div *ngIf=\"shouldShowFdaStatus(status)\" class=\"status-filter-chip\"\n                                            [class.selected]=\"status.fda\" (click)=\"toggleStatus(status, 'fda')\">\n                                            <div class=\"status-filter-text\">{{ status.status }}</div>\n                                        </div>\n                                    </div>\n                                </div>\n\n                                <div class=\"status-group-title final-title\">Final Status</div>\n\n                                <div class=\"status-chip-wrapper\">\n                                    <div *ngFor=\"let status of filteredStatusList\">\n                                        <div *ngIf=\"status.status === 'Final Status'\" class=\"status-filter-chip\"\n                                            [class.selected]=\"status.pda || status.fda\"\n                                            (click)=\"toggleStatus(status, 'both')\">\n                                            <div class=\"status-filter-text\">Final Status</div>\n                                        </div>\n                                    </div>\n                                </div>\n                            </div>\n\n                            <div *ngIf=\"filteredStatusList.length === 0 && statusList.length > 0\" class=\"no-data\">\n                                <p>No matching statuses found</p>\n                            </div>\n\n                            <div *ngIf=\"statusList.length === 0\" class=\"no-data\">\n                                <p>No statuses available</p>\n                            </div>\n\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 2\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearPICFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 25px;\" *ngIf=\"picList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search PICs...\"\n                                [(ngModel)]=\"picSearchText\" (input)=\"filterPICs()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let pic of filteredPICList\">\n                                <mat-checkbox [(ngModel)]=\"pic.selected\" disableRipple (change)=\"onPICChange(pic)\"\n                                    color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ pic.user_name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredPICList.length === 0 && picList.length > 0\" class=\"no-data\">\n                                <p>No matching PICs found</p>\n                            </div>\n                            <div *ngIf=\"picList.length === 0\" class=\"no-data\">\n                                <p>No PICs available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 3\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearVesselFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 30px;\" *ngIf=\"vesselList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search vessels...\"\n                                [(ngModel)]=\"vesselSearchText\" (input)=\"filterVessels()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let vessel of filteredVesselList\">\n                                <mat-checkbox [(ngModel)]=\"vessel.selected\" disableRipple\n                                    (change)=\"onVesselChange(vessel)\" color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ vessel.name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredVesselList.length === 0 && vesselList.length > 0\" class=\"no-data\">\n                                <p>No matching vessels found</p>\n                            </div>\n                            <div *ngIf=\"vesselList.length === 0\" class=\"no-data\">\n                                <p>No vessels available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 4\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearPortFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 30px;\" *ngIf=\"portList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search ports...\"\n                                [(ngModel)]=\"portSearchText\" (input)=\"filterPorts()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let port of filteredPortList\">\n                                <mat-checkbox [(ngModel)]=\"port.selected\" disableRipple (change)=\"onPortChange(port)\"\n                                    color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ port.name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredPortList.length === 0 && portList.length > 0\" class=\"no-data\">\n                                <p>No matching ports found</p>\n                            </div>\n                            <div *ngIf=\"portList.length === 0\" class=\"no-data\">\n                                <p>No ports available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 5\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearCountryFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 30px;\" *ngIf=\"countryList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search countries...\"\n                                [(ngModel)]=\"countrySearchText\" (input)=\"filterCountries()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let country of filteredCountryList\">\n                                <mat-checkbox [(ngModel)]=\"country.selected\" disableRipple\n                                    (change)=\"onCountryChange(country)\" color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ country.country_name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredCountryList.length === 0 && countryList.length > 0\" class=\"no-data\">\n                                <p>No matching countries found</p>\n                            </div>\n                            <div *ngIf=\"countryList.length === 0\" class=\"no-data\">\n                                <p>No countries available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 6\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearPortAgentFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 30px;\" *ngIf=\"portAgentList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search port agents...\"\n                                [(ngModel)]=\"searchText\" (input)=\"filterPortAgents()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let agent of filteredPortAgentList\">\n                                <mat-checkbox [(ngModel)]=\"agent.selected\" disableRipple\n                                    (change)=\"onPortAgentChange(agent)\" color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ agent.company_name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredPortAgentList.length === 0 && portAgentList.length > 0\" class=\"no-data\">\n                                <p>No matching port agents found</p>\n                            </div>\n                            <div *ngIf=\"portAgentList.length === 0\" class=\"no-data\">\n                                <p>No port agents available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 7\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearClientFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"search-box\" style=\"margin-top: 30px;\" *ngIf=\"clientList.length > 0\">\n                            <mat-icon class=\"search-icon-1\">search</mat-icon>\n                            <input type=\"text\" class=\"search-input\" placeholder=\"Search clients...\"\n                                [(ngModel)]=\"clientSearchText\" (input)=\"filterClients()\">\n                        </div>\n                        <div class=\"checkbox-list\">\n                            <div class=\"checkbox-item\" *ngFor=\"let client of filteredClientList\">\n                                <mat-checkbox [(ngModel)]=\"client.selected\" disableRipple\n                                    (change)=\"onClientChange(client)\" color=\"primary\" class=\"custom-mat-checkbox\">\n                                    {{ client.name }}\n                                </mat-checkbox>\n                            </div>\n                            <div *ngIf=\"filteredClientList.length === 0 && clientList.length > 0\" class=\"no-data\">\n                                <p>No matching clients found</p>\n                            </div>\n                            <div *ngIf=\"clientList.length === 0\" class=\"no-data\">\n                                <p>No clients available</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 8\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearVoyageFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div *ngIf=\"selectedVoyages.length > 0\"\n                            style=\"display: flex; flex-wrap: wrap; align-content: flex-start; gap: 8px; margin-top: 20px; margin-bottom: 16px; max-height: 235px; overflow-y: auto;\">\n                            <mat-chip *ngFor=\"let voyage of selectedVoyages\" (removed)=\"removeVoyage(voyage)\">\n                                {{ voyage }}\n                                <mat-icon matChipRemove>cancel</mat-icon>\n                            </mat-chip>\n                        </div>\n                        <mat-form-field appearance=\"outline\" style=\"width: 100%;\">\n                            <mat-label>Search voyages</mat-label>\n                            <input type=\"text\" matInput [formControl]=\"voyageControl\" [matAutocomplete]=\"autoVoyage\"\n                                (keydown.enter)=\"addCustomVoyage()\">\n                            <mat-autocomplete #autoVoyage=\"matAutocomplete\" (optionSelected)=\"onVoyageSelected($event)\">\n                                <mat-option *ngFor=\"let voyage of filteredVoyageList\" [value]=\"voyage.name\">\n                                    {{ voyage.name }}\n                                </mat-option>\n                                <mat-option *ngIf=\"voyageControl.value && filteredVoyageList.length === 0\"\n                                    [value]=\"voyageControl.value\">\n                                    Add \"{{ voyageControl.value }}\"\n                                </mat-option>\n                            </mat-autocomplete>\n                        </mat-form-field>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 9\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearLossPreventionFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"checkbox-list\" style=\"margin-top: 30px;\">\n                            <div *ngFor=\"let lp of lossPreventionList\"\n                                style=\"margin-bottom: 16px; padding: 12px; border: 1px solid #e5e7eb; border-radius: 8px;\">\n                                <div style=\"display: flex; align-items: center; margin-bottom: 8px;\">\n                                    <mat-checkbox [(ngModel)]=\"lp.enabled\" (change)=\"onLossPreventionChange()\"\n                                        color=\"primary\" class=\"custom-mat-checkbox\">\n                                        {{ lp.type }}\n                                    </mat-checkbox>\n                                </div>\n                                <div *ngIf=\"lp.enabled\" style=\"display: flex; gap: 40px; margin-left: 32px;\">\n                                    <div style=\"width: 100px;\">\n                                        <label\n                                            style=\"font-size: 12px; color: #6b7280; display: block; margin-bottom: 4px;\">Min</label>\n                                        <input type=\"number\" [(ngModel)]=\"lp.min\" (input)=\"onLossPreventionChange()\"\n                                            placeholder=\"Min value\"\n                                            style=\"width: 100%; padding: 8px; border: 1px solid #d1d5db; border-radius: 4px;\">\n                                    </div>\n                                    <div style=\"width: 100px;\">\n                                        <label\n                                            style=\"font-size: 12px; color: #6b7280; display: block; margin-bottom: 4px;\">Max</label>\n                                        <input type=\"number\" [(ngModel)]=\"lp.max\" (input)=\"onLossPreventionChange()\"\n                                            placeholder=\"Max value\"\n                                            style=\"width: 100%; padding: 8px; border: 1px solid #d1d5db; border-radius: 4px;\">\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"tab-content\" *ngIf=\"activeTabIndex === 10\" [@slideDown]>\n                    <button class=\"clear-section-button\" (click)=\"clearOverDueFilter()\">\n                        <mat-icon>clear</mat-icon> Clear\n                    </button>\n                    <div class=\"filter-options\">\n                        <div class=\"checkbox-list\" style=\"margin-top: 30px;\">\n                            <div *ngFor=\"let od of overDueList\"\n                                style=\"margin-bottom: 16px; padding: 12px; border: 1px solid #e5e7eb; border-radius: 8px;\">\n                                <div style=\"font-weight: 500; color: #374151; margin-bottom: 8px;\">\n                                    {{ od.type }}\n                                </div>\n                                <div style=\"display: flex; gap: 40px;\">\n                                    <div style=\"width: 100px;\">\n                                        <label\n                                            style=\"font-size: 12px; color: #6b7280; display: block; margin-bottom: 4px;\">Min</label>\n                                        <input type=\"number\" [(ngModel)]=\"od.min\" (input)=\"onOverDueChange()\"\n                                            placeholder=\"Min value\"\n                                            style=\"width: 100%; padding: 8px; border: 1px solid #d1d5db; border-radius: 4px;\">\n                                    </div>\n                                    <div style=\"width: 100px;\">\n                                        <label\n                                            style=\"font-size: 12px; color: #6b7280; display: block; margin-bottom: 4px;\">Max</label>\n                                        <input type=\"number\" [(ngModel)]=\"od.max\" (input)=\"onOverDueChange()\"\n                                            placeholder=\"Max value\"\n                                            style=\"width: 100%; padding: 8px; border: 1px solid #d1d5db; border-radius: 4px;\">\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n    <div class=\"clear-section\">\n        <button class=\"clear-button\" (click)=\"clearAllFilters()\">\n            Clear All\n        </button>\n        <button class=\"apply-button\" (click)=\"applyFilters()\">\n            Apply Filters\n        </button>\n    </div>\n</section>","import { Component, Inject, OnInit } from \"@angular/core\";\nimport { MatIcon } from \"@angular/material/icon\";\nimport { MatLabel } from \"@angular/material/form-field\";\nimport { MatInputModule } from \"@angular/material/input\";\nimport { MAT_DIALOG_DATA, MatDialogRef } from \"@angular/material/dialog\";\nimport { CommonModule } from \"@angular/common\";\nimport { FormArray, FormBuilder, FormGroup } from \"@angular/forms\";\nimport { ReactiveFormsModule } from '@angular/forms';\nimport { MatCheckboxModule } from '@angular/material/checkbox';\nimport { SnackbarService } from \"../../shared/snack-bar/snack-bar.service\";\n\n\n@Component({\n    selector: 'app-email-dialog',\n    standalone: true,\n    imports: [MatIcon, MatInputModule, MatLabel, CommonModule, ReactiveFormsModule, MatCheckboxModule],\n    templateUrl: './display-column-dialog.html',\n    styleUrls: ['./display-column-dialog.css']\n})\nexport class displayColumnDialogComponent implements OnInit {\n    form!: FormGroup;\n    columnsToDisplay: any[] = [];\n    applyCss: boolean = false;\n    isPdfDisabled: boolean = false;\n\n    constructor(private dialogRef: MatDialogRef<displayColumnDialogComponent>,\n        @Inject(MAT_DIALOG_DATA) public data: any, private fb: FormBuilder, private snackBar: SnackbarService) {\n        this.columnsToDisplay = this.data.columns || [];\n        this.form = this.fb.group({\n            columns: this.fb.array([])\n        });\n    }\n\n\n\n    ngOnInit() {\n        const formArray = this.columnsToDisplay.map(() => this.fb.control(false));\n        this.form.setControl('columns', this.fb.array(formArray));\n        \n        this.columns.valueChanges.subscribe(() => {\n            this.checkPdfValidity();\n        });\n    }\n\n    get columns(): FormArray {\n        return this.form.get('columns') as FormArray;\n    }\n\n    onClose() {\n        this.dialogRef.close();\n    }\n    allSelected(): boolean {\n        return this.columns.controls.every(control => control.value === true);\n    }\n\n    toggleAll(event: any) {\n        const checked = event.checked;\n        this.columns.controls.forEach(control => control.setValue(checked));\n    }\n    isApplyCss(): boolean {\n        return this.applyCss;\n    }\n\n    toggleApplyCss(event: any) {\n        this.applyCss = event.checked;\n    }\n\n    getColumnsWithSelection(): { label: string; field: string; selected: boolean }[] {\n        return this.columns.controls.map((control, i) => ({\n            label: this.columnsToDisplay[i].label,\n            field: this.columnsToDisplay[i].field,\n            selected: control.value\n        }));\n    }\n\n    exportData(type: string) {\n        if (!this.columns.controls.some(control => control.value === true)) {\n            this.snackBar.showError('Please select at least one column')\n            return;\n        }\n\n        const selectedColumns = this.getColumnsWithSelection().filter(col => col.selected);\n        \n        if (type === 'pdf' && this.data.pdfExportService) {\n            const validation = this.data.pdfExportService.validatePdfColumns(selectedColumns);\n            if (!validation.valid) {\n                this.snackBar.showError(validation.message);\n                return;\n            }\n        }\n\n        this.dialogRef.close({\n            exportType: type,\n            columns: this.getColumnsWithSelection(),\n            applyCss: this.applyCss\n        });\n    }\n\n    checkPdfValidity() {\n        const selectedColumns = this.getColumnsWithSelection().filter(col => col.selected);\n        if (selectedColumns.length === 0) {\n            this.isPdfDisabled = false;\n            return;\n        }\n        \n        if (this.data.pdfExportService) {\n            const validation = this.data.pdfExportService.validatePdfColumns(selectedColumns);\n            this.isPdfDisabled = !validation.valid;\n        }\n    }\n\n}","<form [formGroup]=\"form\" class=\"dialog-container\">\n    <div class=\"dialog-header\">\n        <h6>Select Columns to export</h6>\n        <p *ngIf=\"isPdfDisabled\" class=\"pdf-warning\">Too many columns selected. Please reduce column selection for PDF\n            export.</p>\n        <button mat-icon-button class=\"close-icon\" (click)=\"onClose()\">\n            <mat-icon>close</mat-icon>\n        </button>\n    </div>\n\n    <div formArrayName=\"columns\" class=\"display-section\">\n        <div class=\"select-all section\" style=\"grid-column: span 2;\">\n            <mat-checkbox [checked]=\"allSelected()\" (change)=\"toggleAll($event)\">\n                <span style=\"font-weight: bold;\">Select All</span>\n            </mat-checkbox>\n        </div>\n\n        <div class=\"select-all section\" style=\"grid-column: span 2;\">\n            <mat-checkbox [checked]=\"isApplyCss()\" (change)=\"toggleApplyCss($event)\">\n                <span style=\"font-weight: bold;\">Highlight Over Due</span>\n            </mat-checkbox>\n        </div>\n\n        <div *ngFor=\"let column of columnsToDisplay; let i = index\">\n            <mat-checkbox [formControlName]=\"i\">\n                {{ column.label }}\n            </mat-checkbox>\n        </div>\n    </div>\n\n    <!-- Buttons aligned bottom right -->\n    <div class=\"button-section\">\n        <button type=\"button\" class=\"button\" (click)=\"exportData('pdf')\" [disabled]=\"isPdfDisabled\">PDF</button>\n        <button type=\"button\" class=\"button\" (click)=\"exportData('excel')\">Excel</button>\n    </div>\n\n</form>","import { Component, Input, Output, EventEmitter, OnInit, inject } from '@angular/core';\nimport { CommonModule } from '@angular/common';\nimport { MatIconModule } from '@angular/material/icon';\nimport { MatDividerModule } from '@angular/material/divider';\nimport { DomSanitizer } from '@angular/platform-browser';\nimport { MatDialog } from '@angular/material/dialog';\nimport { FileUploadService } from '../file-upload/file-upload.service';\nimport { SnackbarService } from '../../shared/snack-bar/snack-bar.service';\nimport { LoaderService } from '../../shared/loader/loader.service';\nimport { FileUploadData } from '../file-upload/file-upload.component';\nimport { FileDisplayComponent } from '../file-upload/file-display/file-display.component';\n// @ts-ignore\nimport { saveAs } from 'file-saver';\n\n@Component({\n  selector: 'app-floating-file-viewer',\n  standalone: true,\n  imports: [CommonModule, MatIconModule, MatDividerModule],\n  templateUrl: './floating-file-viewer.component.html',\n  styleUrl: './floating-file-viewer.component.css'\n})\nexport class FloatingFileViewerComponent implements OnInit {\n  @Input() disbursementSeq!: number;\n  @Input() disbursementId!: string;\n  @Output() close = new EventEmitter<void>();\n\n  previewFiles: FileUploadData[] = [];\n  pdaPreviewFiles: FileUploadData[] = [];\n  fdaPreviewFiles: FileUploadData[] = [];\n\n  isLoading = false;\n\n  constructor(\n    private fileUploadService: FileUploadService,\n    private snackBar: SnackbarService,\n    private loader: LoaderService,\n    private sanitizer: DomSanitizer,\n    private dialog: MatDialog\n  ) { }\n\n  ngOnInit(): void {\n    if (this.disbursementSeq) {\n      this.getUploadedFiles();\n    }\n  }\n\n  getUploadedFiles(): void {\n    const data = {\n      disbursement_seq: this.disbursementSeq,\n      pda_fda_flag: \"DIS\"\n    };\n    this.loader.show();\n    this.isLoading = true;\n    this.fileUploadService.fileDataFromDb(data).subscribe({\n      next: (res) => {\n        this.assignPreviewFiles(res || []);\n        this.isLoading = false;\n        this.loader.hide();\n\n      },\n      error: (err) => {\n        this.isLoading = false;\n\n        this.loader.hide();\n        const errMsg = err?.error?.error || \"Error fetching files from DB\";\n        this.snackBar.showError(errMsg);\n      }\n    });\n  }\n\n  closeOverlay() {\n    this.close.emit();\n  }\n\n  assignPreviewFiles(res: FileUploadData[]): void {\n    this.pdaPreviewFiles = res.filter(file => file.complete_file_path?.includes('/PDA-'));\n    this.fdaPreviewFiles = res.filter(file => file.complete_file_path?.includes('/FDA-'));\n    this.previewFiles = [...this.pdaPreviewFiles, ...this.fdaPreviewFiles];\n  }\n\n  canPreview(file: FileUploadData): boolean {\n    if ('presigned_url' in file && typeof file.presigned_url === 'string') {\n      const presignedUrl = file.presigned_url;\n      return presignedUrl.includes('.pdf') ||\n        presignedUrl.includes('.png') ||\n        presignedUrl.includes('.jpg') ||\n        presignedUrl.includes('.jpeg');\n    }\n    return false;\n  }\n\n  viewFile(file: FileUploadData): void {\n    if (this.canPreview(file)) {\n      if ('presigned_url' in file && typeof file.presigned_url === 'string') {\n        this.previewWithRetry(file, file.presigned_url);\n      } else {\n        this.snackBar.showError('Cannot preview this file.');\n      }\n    }\n  }\n\n  private previewWithRetry(file: FileUploadData, presignedUrl: string): void {\n    fetch(presignedUrl, { method: 'GET' })\n      .then(response => {\n        if (response.status === 403) {\n          this.refreshPresignedUrlAndPreview(file);\n          return;\n        }\n        if (response.status === 404) {\n          this.snackBar.showError('File not found.');\n          return;\n        }\n        if (response.ok) {\n          this.openPreviewDialog(presignedUrl, file.name);\n        } else {\n          throw new Error(`HTTP ${response.status}`);\n        }\n      })\n      .catch(() => this.snackBar.showError('Cannot preview this file.'));\n  }\n\n  private refreshPresignedUrlAndPreview(file: FileUploadData): void {\n    const data = { disbursement_seq: this.disbursementSeq, pda_fda_flag: \"DIS\" };\n    this.fileUploadService.fileDataFromDb(data).subscribe({\n      next: (res) => {\n        const updatedFile = res.find((f: any) => f.file_id === file.file_id);\n        if (updatedFile?.presigned_url) {\n          this.openPreviewDialog(updatedFile.presigned_url, file.name);\n        } else {\n          this.snackBar.showError('Unable to refresh preview link.');\n        }\n      },\n      error: () => this.snackBar.showError('Error refreshing preview link.')\n    });\n  }\n\n  private openPreviewDialog(url: string, fileName: string): void {\n    const previewUrl = this.sanitizer.bypassSecurityTrustResourceUrl(url);\n    this.dialog.open(FileDisplayComponent, {\n      data: { url: previewUrl, name: fileName },\n      width: '100vw',\n      height: '100vh',\n      maxHeight: '100vh',\n      maxWidth: '100vw'\n    });\n  }\n\n  downloadFile(file: any): void {\n    this.downloadWithRetry(file, file.presigned_url);\n  }\n\n  private downloadWithRetry(file: any, presignedUrl: string): void {\n    if (!presignedUrl) {\n      this.snackBar.showError('Error while downloading the file.');\n      return;\n    }\n    fetch(presignedUrl)\n      .then(response => {\n        if (response.status === 403) {\n          this.refreshPresignedUrlAndDownload(file);\n          return;\n        }\n        if (response.status === 404) {\n          this.snackBar.showError('File not found.');\n          return;\n        }\n        if (!response.ok) throw new Error(`HTTP ${response.status}`);\n        return response.blob();\n      })\n      .then(blob => { if (blob) saveAs(blob, file.name); })\n      .catch(() => this.snackBar.showError('Error while downloading the file.'));\n  }\n\n  private refreshPresignedUrlAndDownload(file: any): void {\n    const data = { disbursement_seq: this.disbursementSeq, pda_fda_flag: \"DIS\" };\n    this.fileUploadService.fileDataFromDb(data).subscribe({\n      next: (res) => {\n        const updatedFile = res.find((f: any) => f.file_id === file.file_id);\n        if (updatedFile?.presigned_url) {\n          this.downloadWithRetry(file, updatedFile.presigned_url);\n        } else {\n          this.snackBar.showError('Unable to refresh download link.');\n        }\n      },\n      error: () => this.snackBar.showError('Error refreshing download link.')\n    });\n  }\n\n}\n","<div class=\"floating-viewer-container\">\n    <span style=\"font-weight: bold;\">Disbursement Id : {{disbursementId}}</span>\n    <button class=\"close-overlay-btn\" (click)=\"closeOverlay()\">\n        <mat-icon>close</mat-icon>\n    </button>\n    <div class=\"header-loader\" *ngIf=\"isLoading\">\n        <mat-icon class=\"spin-icon\">refresh</mat-icon> Loading files...\n    </div>\n    <div *ngIf=\"!isLoading && previewFiles.length === 0\" class=\"no-data-msg\">\n        No files uploaded.\n    </div>\n\n    <div *ngIf=\"!isLoading && previewFiles.length > 0\" class=\"preview-container\">\n        <!-- PDA Section -->\n        <div class=\"files-column\">\n            <span class=\"section-title\">PDA</span>\n            <div *ngIf=\"pdaPreviewFiles.length\" class=\"files-list\">\n                <div *ngFor=\"let file of pdaPreviewFiles\" class=\"file-item\">\n                    <div class=\"file-content\">\n                        <mat-icon>image</mat-icon>\n                        <div class=\"file-info\">\n                            <div class=\"file-name\" [title]=\"file.name\">{{ file.name }}</div>\n                        </div>\n                    </div>\n                    <div class=\"actions\">\n                        <button type=\"button\" (click)=\"viewFile(file)\" class=\"icon-btn\" [disabled]=\"!canPreview(file)\"\n                            title=\"Preview\">\n                            <mat-icon>visibility</mat-icon>\n                        </button>\n                        <button type=\"button\" (click)=\"downloadFile(file)\" class=\"icon-btn\" title=\"Download\">\n                            <mat-icon>download</mat-icon>\n                        </button>\n                    </div>\n                </div>\n            </div>\n            <div *ngIf=\"pdaPreviewFiles.length === 0\" class=\"no-data-msg mini\">\n                No files uploaded for PDA.\n            </div>\n        </div>\n\n        <mat-divider [vertical]=\"true\" class=\"divider\"></mat-divider>\n\n        <!-- FDA Section -->\n        <div class=\"files-column\">\n            <span class=\"section-title\">FDA</span>\n            <div *ngIf=\"fdaPreviewFiles.length\" class=\"files-list\">\n                <div *ngFor=\"let file of fdaPreviewFiles\" class=\"file-item\">\n                    <div class=\"file-content\">\n                        <mat-icon>image</mat-icon>\n                        <div class=\"file-info\">\n                            <div class=\"file-name\" [title]=\"file.name\">{{ file.name }}</div>\n                        </div>\n                    </div>\n                    <div class=\"actions\">\n                        <button type=\"button\" (click)=\"viewFile(file)\" class=\"icon-btn\" [disabled]=\"!canPreview(file)\"\n                            title=\"Preview\">\n                            <mat-icon>visibility</mat-icon>\n                        </button>\n                        <button type=\"button\" (click)=\"downloadFile(file)\" class=\"icon-btn\" title=\"Download\">\n                            <mat-icon>download</mat-icon>\n                        </button>\n                    </div>\n                </div>\n            </div>\n            <div *ngIf=\"fdaPreviewFiles.length === 0\" class=\"no-data-msg mini\">\n                No files uploaded for FDA.\n            </div>\n        </div>\n    </div>\n</div>","import { Directive, ElementRef, Input, OnInit, OnDestroy, Output, EventEmitter } from '@angular/core';\n\n@Directive({\n  selector: '[appTruncateTooltip]',\n  standalone: true\n})\nexport class TruncateTooltipDirective implements OnInit, OnDestroy {\n  @Input() appTruncateTooltip: string = '';\n  @Input() ariaLabel: string = '';\n  @Output() showCustomTooltip = new EventEmitter<{ text: string; x: number; y: number; tooltipClass?: string }>();\n  @Output() hideCustomTooltip = new EventEmitter<void>();\n\n  private resizeObserver: ResizeObserver | null = null;\n  private isTruncated = false;\n\n  constructor(private el: ElementRef) {}\n\n  ngOnInit() {\n    this.checkTruncation();\n    this.setupResizeObserver();\n    this.el.nativeElement.setAttribute('aria-label', this.ariaLabel || this.appTruncateTooltip);\n    this.setupTooltipListeners();\n  }\n\n  ngOnDestroy() {\n    if (this.resizeObserver) {\n      this.resizeObserver.disconnect();\n    }\n  }\n\n  private checkTruncation() {\n    const element = this.el.nativeElement;\n    this.isTruncated = element.scrollWidth > element.clientWidth;\n  }\n\n  private setupResizeObserver() {\n    this.resizeObserver = new ResizeObserver(() => {\n      this.checkTruncation();\n    });\n    this.resizeObserver.observe(this.el.nativeElement);\n  }\n\n  private setupTooltipListeners() {\n    this.el.nativeElement.addEventListener('mouseenter', () => this.onMouseEnter());\n    this.el.nativeElement.addEventListener('mouseleave', () => this.onMouseLeave());\n  }\n\n  private onMouseEnter() {\n    if (this.isTruncated && this.appTruncateTooltip) {\n      const rect = this.el.nativeElement.getBoundingClientRect();\n      this.showCustomTooltip.emit({\n        text: this.appTruncateTooltip,\n        x: rect.left - 310,\n        y: rect.top,\n        tooltipClass: 'savings-reason-tooltip'\n      });\n    }\n  }\n\n  private onMouseLeave() {\n    this.hideCustomTooltip.emit();\n  }\n}\n","import { Injectable } from '@angular/core';\nimport * as XLSX from 'xlsx-js-style';\n\n@Injectable({\n  providedIn: 'root'\n})\nexport class ExcelExportService {\n\n  exportToExcel(columns: any[], data: any[], applyCss: boolean = false, fileName: string = 'Export') {\n    const excelData = data?.map((row: any) => {\n      const filteredRow: any = {};\n      columns.filter(c => c.selected).forEach((col: any) => {\n        filteredRow[col.label] = row[col.field] ?? '';\n      });\n      return filteredRow;\n    });\n\n    const worksheet: XLSX.WorkSheet = XLSX.utils.json_to_sheet(excelData);\n    const selectedColumns = columns.filter(c => c.selected);\n    worksheet['!cols'] = selectedColumns.map(() => ({ wch: 20 }));\n\n    // Apply header background color\n    selectedColumns.forEach((col, colIndex) => {\n      const cellAddress = XLSX.utils.encode_cell({ r: 0, c: colIndex });\n      if (worksheet[cellAddress]) {\n        worksheet[cellAddress].s = {\n          fill: { fgColor: { rgb: 'FFFF00' } },\n          font: { bold: true }\n        };\n      }\n    });\n\n    // Apply due_color to disbursement_id column\n    if (applyCss) {\n      data.forEach((row: any, rowIndex: number) => {\n\n        if (row.due_color) {\n          selectedColumns.forEach((col: any, colIndex: number) => {\n            const cellAddress = XLSX.utils.encode_cell({\n              r: rowIndex + 1,\n              c: colIndex\n            });\n            if (worksheet[cellAddress]) {\n              worksheet[cellAddress].s = {\n                fill: {\n                  patternType: \"solid\",\n                  fgColor: { rgb: row.due_color.replace('#', '') }\n                },\n              };\n            }\n          });\n        }\n      });\n    }\n\n    const workbook: XLSX.WorkBook = XLSX.utils.book_new();\n    XLSX.utils.book_append_sheet(workbook, worksheet, 'Disbursement');\n    XLSX.writeFile(workbook, `${fileName}_${new Date().toISOString().split('T')[0]}.xlsx`);\n  }\n}\n","function _typeof(o) {\n  \"@babel/helpers - typeof\";\n\n  return _typeof = \"function\" == typeof Symbol && \"symbol\" == typeof Symbol.iterator ? function (o) {\n    return typeof o;\n  } : function (o) {\n    return o && \"function\" == typeof Symbol && o.constructor === Symbol && o !== Symbol.prototype ? \"symbol\" : typeof o;\n  }, _typeof(o);\n}\nexport { _typeof as default };","// DEFLATE is a complex format; to read this code, you should probably check the RFC first:\n// https://tools.ietf.org/html/rfc1951\n// You may also wish to take a look at the guide I made about this program:\n// https://gist.github.com/101arrowz/253f31eb5abc3d9275ab943003ffecad\n// Some of the following code is similar to that of UZIP.js:\n// https://github.com/photopea/UZIP.js\n// However, 