duce((acc: any, col: any, index: number) => {\n        acc[index] = {\n          cellWidth: 'auto',\n          overflow: 'linebreak'\n        };\n        return acc;\n      }, {}),\n      didParseCell: (hookData: any) => {\n        if (applyCss && hookData.section === 'body') {\n          const rowData = data[hookData.row.index];\n          if (rowData?.due_color) {\n            hookData.cell.styles.fillColor = rowData.due_color;\n          }\n        }\n      },\n      didDrawPage: (data: any) => {\n        if (logoImg) {\n          try {\n            doc.addImage(logoImg, 'PNG', 10, 5, 20, 10);\n          } catch (e) {\n            console.error('Error adding logo:', e);\n          }\n        }\n        doc.setFontSize(12);\n        doc.text('Meraki Greatlakes Shipping and Technical', pageWidth / 2, 10, { align: 'center' });\n        doc.setFontSize(10);\n        doc.text('Management L.L.C-FZ', pageWidth / 2, 15, { align: 'center' });\n      },\n      margin: { top: 20, right: 10, bottom: 10, left: 10 }\n    });\n\n    doc.save(`${fileName}_${new Date().toISOString().split('T')[0]}.pdf`);\n  }\n\n  private validatePdfColumns(selectedColumns: any[]): { valid: boolean; message?: string; orientation?: string } {\n    const portraitWidth = 190;\n    const landscapeWidth = 270;\n\n    const totalWidth = selectedColumns.reduce((sum, col) => {\n      const labelLength = col.label?.length || 10;\n      return sum + Math.max(labelLength * 2, 20);\n    }, 0);\n\n    if (totalWidth <= portraitWidth) {\n      return { valid: true, orientation: 'portrait' };\n    } else if (totalWidth <= landscapeWidth) {\n      return { valid: true, orientation: 'landscape' };\n    } else {\n      return {\n        valid: false,\n        message: \"Selected columns are too wide. Try reducing columns\"\n      };\n    }\n  }\n}\n","import { Component, inject, OnDestroy } from '@angular/core';\nimport { MatButtonModule } from '@angular/material/button';\nimport { MatIconModule } from '@angular/m