ooltipDirective\n  ],\n  templateUrl: './disbursment.component.html',\n  styleUrl: './disbursment.component.css',\n})\nexport class DisbursmentComponent implements OnDestroy {\n  loader = inject(LoaderService);\n  private overlay = inject(Overlay);\n  private overlayRef: OverlayRef | null = null;\n\n  isLoading = this.loader.loading();\n  searchTerm: string = '';\n  allDataLoaded = false;\n  dataSource: Disbursment[] = [];\n  columnsToDisplay = columnsToDisplay;\n  columnsToDisplayOnly = this.columnsToDisplay.map(col => col.property);\n  expandedElement: Disbursment | null = null;\n  disbursementdetails: DisbursmentDetails = new DisbursmentDetails({});\n  isExpandedVal: boolean = false;\n  preventScroll: boolean = false;\n\n  currentPage = 1;\n  pageSize = 50;\n  totalCount = 0;\n  appliedFilters: any = null;\n  tooltipData: { text: string; x: number; y: number; tooltipClass?: string } | null = null;\n  private searchSubject = new Subject<string>();\n  roleId: number = 0;\n  ColumnsTodisplayInExportData = ColumnsTodisplayInExportData\n\n  constructor(private disbursementService: DisbursementService, private snackbar: SnackbarService, private dialog: MatDialog, private router: Router, private excelExportService: ExcelExportService, private pdfExportService: PdfExportService) {\n    // Setup debounce for search\n    this.searchSubject\n      .pipe(\n        debounceTime(1000)\n      )\n      .subscribe(() => {\n        this.onSearch();\n      });\n  }\n\n  ngOnInit() {\n    const storedRoleId = sessionStorage.getItem('roleId');\n    this.roleId = storedRoleId ? +storedRoleId : 0;\n    this.columnsToDisplay = this.columnsToDisplay.filter((column: any) => column.access.includes(this.roleId));\n    this.columnsToDisplayOnly = this.columnsToDisplay.map(col => col.property);\n    if (this.roleId === 3) {\n      this.getClientDisbursmentDataFromDb(true)\n    }\n    else {\n      this.getDisbursmentDataFromDb(true);\n    }\n\n  }\n\n  ngOnDestroy() {\n    this.searchSubject.