edFilters.filter) {\n      body.filter = this.appliedFilters.filter;\n    }\n\n    this.loader.show();\n    this.disbursementService.getClientDisbursementData(body).subscribe({\n      next: (response: { data: Disbursment[], total_count: number }) => {\n        this.totalCount = response.total_count;\n        this.dataSource = [...this.dataSource, ...response.data];\n        this.dataSource = this.dataSource.map(item => {\n          const mappedItem = {\n            ...item,\n            eta: formatDate(item.eta),\n            etd: formatDate(item.etd),\n            due_comment: item.due_comment || '',\n            due_color: item.due_color || ''\n          };\n          return mappedItem;\n        });\n        if (this.dataSource.length >= this.totalCount) {\n          this.allDataLoaded = true;\n        }\n\n        this.currentPage++;\n        this.loader.hide();\n      },\n      error: (error) => {\n        console.error('Error fetching disbursement data:', error);\n        this.loader.hide();\n      }\n    });\n  }\n\n\n\n  /** Handles changes in the disbursement details from the child component. */\n  handleDisbursementChange(updatedDisbursement: DisbursmentDetails) {\n    // pass the updated disbursement data to the service or perform any necessary actions\n    this.loader.show()\n    this.disbursementService.disbursementDataToDb(updatedDisbursement).subscribe({\n      next: (response) => {\n        this.snackbar.showSuccess(response.message);\n        this.loader.hide()\n        // Optionally, you can refresh the data or perform any other actions\n        // this.getDisbursmentDataFromDb();\n      },\n      error: (error) => {\n        this.snackbar.showError('Error updating disbursement details');\n        this.loader.hide()\n      }\n    });\n  }\n\n  /** Checks whether an element is expanded. */\n  isExpanded(element: Disbursment) {\n    return this.expandedElement === element;\n  }\n\n  /** Toggles the expanded state of an element. */\n  toggle(element: Disbursment) {\n    // this.isExpandedVal = !this.isExpandedVal;\n    if (this.roleId !== 3) {\n      const wasExpanded = this.isExpanded(element);\n      this.expandedElement = wasExpanded ? null : element;\n      this.isExpandedVal = !wasExpanded;\n    }\n\n  }\n\n\n  // method to search the record globally\n  onSearch() {\n    this.appliedFilters = null;\n    if (this.roleId === 3) {\n      this.getClientDisbursmentDataFromDb(true)\n    }\n    else {\n      this.getDisbursmentDataFromDb(true);\n    }\n  }\n\n  // method to  clear the search term\n  clearSearch() {\n    this.searchTerm = '';\n    this.appliedFilters = null;\n    if (this.roleId === 3) {\n      this.getClientDisbursmentDataFromDb(true)\n    }\n    else {\n      this.getDisbursmentDataFromDb(true);\n    }\n  }\n\n\n  // method to call the api on scroll\n  onManualScroll(): void {\n    const scrollContainer = document.querySelector('.table-container');\n    if (scrollContainer) {\n      const scrollPosition = scrollContainer.scrollTop + scrollContainer.clientHeight;\n      const scrollHeight = scrollContainer.scrollHeight;\n\n      if (\n        scrollPosition >= scrollHeight - 10 &&\n        !this.loader.loading() &&\n        !this.allDataLoaded\n      )\n        if (this.roleId === 3) {\n          this.getClientDisbursmentDataFromDb();\n        }\n        else {\n          this.getDisbursmentDataFromDb();\n        }\n    }\n  }\n\n  /** Toggles the view to show less details. */\n  viewLess() {\n    this.isExpandedVal = false;\n    this.expandedElement = null;\n  }\n\n  navigateToPda() {\n    this.router.navigate(['/layout/pda/create'])\n  }\n\n  navigateToFda() {\n    this.router.navigate(['/layout/fda/create'])\n  }\n\n  openFilterDialog() {\n    const dialogConfig = new MatDialogConfig();\n    dialogConfig.position = { right: '0' };\n    dialogConfig.height = '100%';\n    dialogConfig.width = '45vw';\n    dialogConfig.maxWidth = '45vw';\n    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];\n    dialogConfig.hasBackdrop = true;\n    dialogConfig.data = {\n      // Pass any data you want to the dialog here\n    };\n    const dialogRef = this.dialog.open(DisbursementFilterComponent, dialogConfig);\n\n    dialogRef.afterClosed().subscribe(result => {\n      if (result) {\n        // Apply filters and refresh data\n        this.applyFiltersAndRefresh(result);\n      }\n    });\n  }\n\n  applyFiltersAndRefresh(filters: any) {\n    this.appliedFilters = filters;\n    this.getDisbursmentDataFromDb(true);\n  }\n\n  openColumnDialog() {\n    const dialogRef = this.dialog.open(displayColumnDialogComponent, {\n      disableClose: true,\n      panelClass: 'email-dialog-style',\n      width: '70vw',\n      maxWidth: '95vw',\n      height: '500px',\n      data: {\n        columns: this.ColumnsTodisplayInExportData,\n        pdfExportService: this.pdfExportService\n      }\n    });\n\n    dialogRef.afterClosed().subscribe(result => {\n      if (result) {\n        const body: any = {\n          query: this.searchTerm.trim(),\n          page: this.currentPage,\n          page_size: this.pageSize\n        }\n\n        if (this.appliedFilters && this.appliedFilters.filter) {\n          body.filter = this.appliedFilters.filter;\n        }\n        this.loader.show();\n        this.disbursementService.getDisbursementDataToExport(body).subscribe({\n          next: (response: any) => {\n            let data = response?.data || response;\n            data = this.formatDateFields(data);\n            if (result.exportType === 'excel') {\n              this.excelExportService.exportToExcel(result.columns, data, result.applyCss, 'Disbursement_List');\n            }\n            else if (result.exportType === 'pdf') {\n              this.pdfExportService.exportToPdf(result.columns, data, result.applyCss, 'Disbursement_List');\n            }\n            this.loader.hide();\n          },\n          error: (error) => {\n            console.error('Error exporting data:', error);\n            this.snackbar.showError('Failed to export data');\n            this.loader.hide();\n          }\n        })\n\n      }\n    });\n  }\n\n\n\n  showFilePreview(element: Disbursment, event: MouseEvent) {\n    if (this.overlayRef) {\n      this.overlayRef.dispose();\n      this.overlayRef = null;\n    }\n\n    const positionStrategy = this.overlay.position()\n      .global()\n      .centerHorizontally()\n      .centerVertically();\n\n    this.overlayRef = this.overlay.create({\n      positionStrategy,\n      hasBackdrop: true,\n      backdropClass: 'cdk-overlay-dark-backdrop',\n      scrollStrategy: this.overlay.scrollStrategies.block()\n    });\n\n    this.overlayRef.backdropClick().subscribe(() => {\n      this.hideFilePreview();\n    });\n\n    const portal = new ComponentPortal(FloatingFileViewerComponent);\n    const componentRef = this.overlayRef.attach(portal);\n    componentRef.instance.disbursementSeq = element.disbursement_seq;\n    componentRef.instance.disbursementId = element.disbursement_id;\n\n    // Listen for manual close from the floating viewer\n    const closeSub = componentRef.instance.close.subscribe(() => {\n      this.hideFilePreview();\n      closeSub.unsubscribe();\n    });\n  }\n\n  hideFilePreview() {\n    if (this.overlayRef) {\n      this.overlayRef.dispose();\n      this.overlayRef = null;\n    }\n  }\n\n  showTooltip(element: Disbursment, event: MouseEvent) {\n    if (element.due_comment && element.due_comment !== '') {\n      const rect = (event.target as HTMLElement).getBoundingClientRect();\n      this.tooltipData = {\n        text: element.due_comment,\n        x: rect.right + 10,\n        y: rect.top\n      };\n    }\n  }\n\n  hideTooltip() {\n    this.tooltipData = null;\n  }\n\n  formatDateFields(data: any[], dateFields: string[] = ['agency_nomination_date', 'pda_processing_date', 'fda_processing_date', 'eta', 'etd', 'fda_receive_date', 'pda_receive_date']): any[] {\n    return data.map((row: any) => {\n      const newRow = { ...row };\n      dateFields.forEach(field => {\n        if (newRow[field]) newRow[field] = formatDate(newRow[field]);\n      });\n      return newRow;\n    });\n  }\n\n  onDelete(element: Disbursment, type: string) {\n    const PDAORFDA = element.fda_id && element.fda_state != 'D' ? 'FDA' : 'PDA';\n    const showCheckbox = element.pda_status.toLowerCase().includes('request');\n    const status = PDAORFDA === 'PDA' ? element.pda_status : element.fda_status;\n    const dialogRef = this.dialog.open(ConfirmationDialogComponent, {\n      disableClose: true,\n      panelClass: 'sweet-alert-style',\n      data: {\n        header: `Confirm ${type === 'delete' ? 'Delete' : 'InActive'}`,\n        text: type === 'delete'\n          ? `Are you sure you want to delete the ${PDAORFDA} for Disbursement ID: ${element.disbursement_id} with status: ${status}?   This action cannot be undone.`\n          : `Are you sure you want to inactivate the ${PDAORFDA} for Disbursement ID:  ${element.disbursement_id} and status:${status}?`,\n        showCheckbox: showCheckbox,\n        checkboxText: 'confirm the deletion'\n      }\n    });\n    dialogRef.afterClosed().subscribe(result => {\n      if (result) {\n        this.deleteOrInActivateRecord(element, type);\n      }\n    });\n  }\n\n  deleteOrInActivateRecord(element: Disbursment, type: string) {\n    const params = {\n      disbursement_seq: element.disbursement_seq,\n      pda_id: element.pda_id,\n      fda_id: element.fda_id,\n      state: type === 'delete' ? \"D\" : \"N\"\n    }\n    this.loader.show();\n    this.disbursementService.deleteOrInActivateDisbursement(params).subscribe({\n      next: (response) => {\n        this.loader.hide();\n        this.snackbar.showSuccess(response.message);\n        if (this.roleId === 3) {\n          this.getClientDisbursmentDataFromDb(true)\n        }\n        else {\n          this.getDisbursmentDataFromDb(true);\n        }\n      },\n      error: (error) => {\n        this.loader.hide();\n        this.snackbar.showError(error.message);\n      }\n    })\n\n  }\n}\n","<div style=\"overflow-x: hidden;\" class=\"theme-dark\">\n    <div class=\"topbar topbar-margin\">\n        <div class=\"search-section\" style=\"margin-left: 10px;\">\n            <mat-form-field class=\"search-bar\" appearance=\"outline\" style=\"margin-bottom: 0px;\">\n                <!-- <mat-label>Search disbursement ...</mat-label> -->\n                <input matInput placeholder=\"Search disbursement ...\" [(ngModel)]=\"searchTerm\"\n                    (input)=\"inputSearch()\" />\n            </mat-form-field>\n        </div>\n        <div>\n\n            <button mat-raised-button color=\"primary\" class=\"add-button button-margin\" (click)=\"navigateToPda()\"\n                *ngIf=\"roleId !== 3\">\n                Add PDA\n            </button>\n            <button mat-raised-button color=\"primary\" class=\"add-button button-margin\" (click)=\"navigateToFda()\"\n                *ngIf=\"roleId !== 3\">\n                Add FDA\n            </button>\n            <button mat-raised-button color=\"primary\" class=\"add-button button-margin\" *ngIf=\"roleId !== 3\"\n                (click)=\"openColumnDialog()\">\n                <mat-icon fontSet=\"material-symbols-outlined\">insert_drive_file</mat-icon>\n                Export\n            </button>\n            <button mat-icon-button class=\"filter-button mat-elevation-z4\" (click)=\"openFilterDialog()\"\n                *ngIf=\"roleId !== 3\">\n                <span class=\"avatar-circle\">\n                    <mat-icon fontSet=\"material-symbols-outlined\"\n                        style=\"margin: 4px;margin-top: 11px;\">filter_alt</mat-icon>\n                </span>\n            </button>\n        </div>\n    </div>\n\n    <div style=\"overflow-x: auto; position: relative;\" *ngIf=\"dataSource as data\">\n        <ng-container *ngIf=\"data.length > 0; else noData\">\n            <div class=\"table-container\" (scroll)=\"onManualScroll()\"\n                style=\"max-height: 86vh!important; overflow-y: auto;\">\n                <table mat-table [dataSource]=\"dataSource\" multiTemplateDataRows class=\"mat-elevation-z8 disbursement-table\"\n                    style=\"overflow: visible;\">\n\n                    @for (column of columnsToDisplay; track column) {\n                    <ng-container matColumnDef=\"{{column.property}}\"\n                        [sticky]=\"column.property === 'eye_icon' || column.property === 'disbursement_id'\">\n                        <th mat-header-cell *matHeaderCellDef\n                            [ngStyle]=\"column.property === 'eye_icon' ? {'width': '35px', 'padding': '0', 'border-right': 'none'} : column.property === 'disbursement_id' ? {'min-width': '130px'} : {}\">\n                            {{column.name}}</th>\n\n                        @if(column.property=='eye_icon') {\n                        <td mat-cell *matCellDef=\"let element\"\n                            style=\"width: 35px; padding: 0 0 0 10px; border-right: none; z-index: 10;\"\n                            (click)=\"toggle(element); $event.stopPropagation()\">\n                            <mat-icon fontSet=\"material-symbols-outlined\"\n                                class=\"file-preview-icon\"\n                                title=\"View Uploaded Files\"\n                                (click)=\"showFilePreview(element, $event); $event.stopPropagation()\">\n                                visibility\n                            </mat-icon>\n                        </td>\n                        }\n                        <!--  [ngStyle]=\"{'background-color': element.due_color || ''}\" -->\n                        @else if(column.property=='disbursement_id') {\n                        <td mat-cell *matCellDef=\"let element\"\n                            style=\"text-align: left; padding-left: 0; border-left: none; z-index: 9;\" \n                            [attr.style]=\"(element.due_color ? 'background-color: ' + element.due_color + ' !important;' : '') +\n                            (element.due_color ? ' color: #000000 !important;' : '!ffffff !important;')\"\n                            (click)=\"toggle(element); $event.stopPropagation()\">\n                            <div style=\"display: flex; align-items: center; justify-content: flex-start; gap: 8px;\">\n                                <div\n                                    style=\"width: 20px; height: 20px; display: inline-flex; justify-content: center; align-items: center;\">\n                                    <mat-icon *ngIf=\"element.due_comment && element.due_comment !== 'NA'\"\n                                        class=\"due-info-icon\" (mouseenter)=\"showTooltip(element, $event)\"\n                                        (mouseleave)=\"hideTooltip()\"\n                                        style=\"font-size: 20px; width: 20px; height: 20px; cursor: help;\">\n                                        info\n                                    </mat-icon>\n                                </div>\n                                <span style=\"white-space: nowrap; font-weight: bold;\">{{element[column.property]}}</span>\n                            </div>\n                        </td>\n                        }\n                        @else if(column.property==='loss_prevented_reason') {\n                        <td mat-cell *matCellDef=\"let element\" style=\"text-align: center; padding: 8px;\"\n                            (click)=\"toggle(element); $event.stopPropagation()\">\n                            <span class=\"savings-reason-cell\" [appTruncateTooltip]=\"element[column.property]\"\n                                [ariaLabel]=\"'Savings Reason: ' + element[column.property]\"\n                                (showCustomTooltip)=\"tooltipData = $event\" (hideCustomTooltip)=\"tooltipData = null\">\n                                {{element[column.property]}}\n                            </span>\n                        </td>\n                        }\n                        @else if(column.property!='pda_status'&&column.property!='fda_status' &&\n                        column.property!='final_status' &&\n                        column.property!='action' && column.property!='files') {<td mat-cell *matCellDef=\"let element\"\n                            style=\"text-align: center;\" (click)=\"toggle(element); $event.stopPropagation()\">\n                            {{element[column.property]}}</td>}\n\n                        @else if(column.property==='action') {<td mat-cell *matCellDef=\"let element\"\n                            style=\"text-align: center; padding: 4px;\">\n                            <div style=\"display: flex; gap: 8px; justify-content: center;\">\n                                <div\n                                    style=\"min-width: 24px; display: flex; align-items: center; justify-content: center;\">\n                                    <mat-icon matTooltip=\"InActivate\"\n                                        *ngIf=\"element.status === 'PDA Completed' && element.pda_state !== 'N'\"\n                                        (click)=\"onDelete(element, 'inactive'); $event.stopPropagation()\"\n                                        style=\"color: #ffa375; cursor: pointer;\"> highlight_off</mat-icon>\n                                    <mat-icon *ngIf=\"element.pda_state === 'N'\" matTooltip=\"InActivated\"\n                                        fontSet=\"material-symbols-outlined\" style=\"color: #202223;\">\n                                        do_not_disturb_on\n                                    </mat-icon>\n                                </div>\n                                <div style=\"min-width: 24px; display: flex; align-items: center; justify-content: center;\"\n                                    *ngIf=\"roleId === 1\">\n                                    <mat-icon matTooltip=\"Delete\"\n                                        (click)=\"onDelete(element, 'delete'); $event.stopPropagation()\"\n                                        style=\"color: red; cursor: pointer;\">delete</mat-icon>\n                                </div>\n                            </div>\n                        </td>}\n                        @else{ <td mat-cell *matCellDef=\"let element\" style=\"text-align: center;\"\n                            (click)=\"toggle(element); $event.stopPropagation()\">\n                            <span class=\"statusColumn\" \n                                [attr.style]=\" \n                                'background: ' +\n                                    (column.property === 'pda_status'\n                                    ? element.pda_status_background_color\n                                    : column.property === 'fda_status'\n                                    ? element.fda_status_background_color\n                                    : column.property === 'final_status'\n                                    ? element.final_status_background_color\n                                    : element.status_background_color) + '!important;' +\n                                'color: ' +\n                                    (column.property === 'pda_status'\n                                    ? element.pda_status_text_color\n                                    : column.property === 'fda_status'\n                                    ? element.fda_status_text_color\n                                    : column.property === 'final_status'\n                                    ? element.final_status_text_color\n                                    : element.status_text_color) +\n                                    ' !important;'\"\n                            >{{element[column.property]}}</span>\n                        </td>}\n                    </ng-container>\n                    }\n\n                    